const rawText = $input.first().json.text;

try {
  // Extrait uniquement le contenu entre les accolades { ... }
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);

  if (!jsonMatch) throw new Error("Aucun objet JSON trouvé");

  const cleanJson = jsonMatch[0];
  const parsedData = JSON.parse(cleanJson);

  return {
    reponse_client: parsedData.reponse_client,
    note_metier: parsedData.note_metier
  };
} catch (error) {
  return {
    error: "Erreur de parsing critique",
    message: error.message,
    raw_received: rawText
  };
}
